      chip.fills = [solid("#FFFFFF", 0.05)];
      chip.strokes = [solid("#FFFFFF", 0.12)];
      chip.strokeWeight = 1;
      const ct = figma.createText();
      ct.fontName = F.mono;
      ct.fontSize = 14;
      ct.letterSpacing = { value: 10, unit: "PERCENT" };
      ct.characters = label;
      ct.fills = [solid("#C8CFDA")];
      chip.appendChild(ct);
      chips.appendChild(chip);
