    block(F.disp, 34, "Getting started", "#F2F4F8");
    block(F.body, 16, "Thanks for picking up Helix — a crypto / Web3 design system for exchanges, wallets, DeFi dashboards and NFT marketplaces.", "#9AA4B2");
